        ll_lengths[i] = 8;
    for (i = 144; i < 256; i++)
        ll_lengths[i] = 9;
    for (i = 256; i < 280; i++)
        ll_lengths[i] = 7;
    for (i = 280; i < 288; i++)
        ll_lengths[i] = 8;
    for (i = 0; i < 32; i++)
